import { describe, expect, it } from 'vitest';
import {
  BANDS,
  buildLinkBudgetCertificate,
  dishGainDbi,
  signalAmplitudeForEbN0,
  friisPathLossDb,
  linkBudget,
  LINK_BUDGET_CERT_VERSION,
} from './link-budget';

describe('link-budget', () => {
  it('Friis path loss is monotone in distance and frequency', () => {
    expect(friisPathLossDb(2e8, BANDS['x-down'])).toBeGreaterThan(
      friisPathLossDb(1e8, BANDS['x-down']),
    );
    expect(friisPathLossDb(1e8, BANDS['x-down'])).toBeGreaterThan(
      friisPathLossDb(1e8, BANDS['ism433']),
    );
  });

  it('34 m X-band dish gain is in the DSN ballpark (~67 dBi)', () => {
    const g = dishGainDbi(34, BANDS['x-down']);
    expect(g).toBeGreaterThan(60);
    expect(g).toBeLessThan(72);
  });

  it('a Moon-class link closes with a big margin; Proxima does not', () => {
    const common = {
      freqHz: BANDS['x-down'],
      txPowerDbm: 43,
      txDishM: 4,
      rxDishM: 34,
      systemNoiseTempK: 30,
      dataRateBps: 1000,
      mod: 'mfsk8' as const,
      fec: 'rs+conv' as const,
      whipReplicas: 4,
    };
    const moon = linkBudget({ ...common, distanceM: 384_400_000 });
    expect(moon.marginCloses).toBe(true);
    expect(moon.marginDb).toBeGreaterThan(40);

    const proxima = linkBudget({ ...common, distanceM: 4.0167e16 });
    expect(proxima.marginCloses).toBe(false);
  });

  it('signalAmplitudeForEbN0 increases as Eb/N0 increases', () => {
    const lo = signalAmplitudeForEbN0(0, 'mfsk8', 256);
    const hi = signalAmplitudeForEbN0(20, 'mfsk8', 256);
    expect(hi).toBeGreaterThan(lo);
  });

  it('certificate carries the honest bench-emulation block', () => {
    const cert = buildLinkBudgetCertificate(
      'mars-mean-xdown',
      {
        distanceM: 225_000_000_000,
        freqHz: BANDS['x-down'],
        txPowerDbm: 43,
        txDishM: 4,
        rxDishM: 34,
        systemNoiseTempK: 30,
        dataRateBps: 1000,
        mod: 'mfsk8',
        fec: 'rs+conv',
        whipReplicas: 4,
      },
      256,
    );
    expect(cert.certificateVersion).toBe(LINK_BUDGET_CERT_VERSION);
    expect(cert.benchEmulation.targetEbN0Db).toBeCloseTo(cert.result.receivedEbN0Db, 6);
    expect(cert.benchEmulation.noiseFillRms).toBeGreaterThan(0);
    expect(cert.benchEmulation.signalAmplitude).toBeGreaterThan(0);
    expect(cert.honest).toContain('Eb/N0-equivalence');
  });
});
